const require_validation = require('./validation.cjs');
const require_findSurahAyahByAyahId = require('./findSurahAyahByAyahId.cjs');

//#region src/getJuzMeta.ts
/**
* Retrieves metadata for a specific Juz of the Quran.
*
* @param juzNum - The Juz number to retrieve metadata for (1-30)
* @param data - The Lists object for the riwaya.
* @returns An object containing the Juz number, first ayah, and last ayah in the Juz
* @throws RangeError If the Juz number is not between 1 and 30
*/
function getJuzMeta(juzNum, data) {
	require_validation.checkValidJuz(juzNum, data.meta);
	const { JuzList } = data;
	const [firstAyahId, nextJuzAyahId] = [JuzList[juzNum], JuzList[juzNum + 1]];
	const lastAyahId = nextJuzAyahId - 1;
	return {
		first: require_findSurahAyahByAyahId.findSurahAyahByAyahId(firstAyahId, data),
		firstAyahId,
		juzNum,
		last: require_findSurahAyahByAyahId.findSurahAyahByAyahId(lastAyahId, data),
		lastAyahId
	};
}

//#endregion
exports.getJuzMeta = getJuzMeta;